parameters.jsCode:
const xml = $input.first().json.data;

const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;

// 重大關鍵字清單
const importantKeywords = [
  '建商', '購地', '重劃', '捷運', 'BOT', '利率', '央行',
  '房價', '地上權', '都更', '容積', '開發', '重大建設',
  '土地標售', '地價', '建照', '預售', '實價登錄', '打房',
  '升息', '降息', '囤房稅', '房地合一'
];

// 分類對照
const categoryMap = [
  { keywords: ['購地', '土地', '地上權', '標售', '地價'], category: '🏗️ 建商購地' },
  { keywords: ['捷運', 'BOT', '重劃', '開發', '建設'], category: '🚇 捷運重劃' },
  { keywords: ['利率', '央行', '升息', '降息', '打房', '囤房', '房地合一'], category: '🏦 利率政策' },
  { keywords: ['都更', '容積', '建照'], category: '🏢 都更容積' },
  { keywords: ['房價', '預售', '實價'], category: '💰 房價動態' }
];

while ((match = itemRegex.exec(xml)) !== null) {
  const itemXml = match[1];

  const titleMatch = itemXml.match(/<title><!\[CDATA\[(.+?)\]\]><\/title>/) || itemXml.match(/<title>(.+?)<\/title>/);
  const linkMatch = itemXml.match(/<link>(.+?)<\/link>/);
  const pubDateMatch = itemXml.match(/<pubDate>(.+?)<\/pubDate>/);
  const sourceMatch = itemXml.match(/<source[^>]*><!\[CDATA\[(.+?)\]\]><\/source>/) || itemXml.match(/<source[^>]*>(.+?)<\/source>/);

  if (titleMatch) {
    const pubDate = pubDateMatch ? new Date(pubDateMatch[1]) : new Date();
    const now = new Date();
    const diffMinutes = (now - pubDate) / 1000 / 60;

    // 只取35分鐘內的新聞（多5分鐘緩衝）
    if (diffMinutes <= 1440) {
      const title = titleMatch[1].trim();

      // 檢查是否包含重要關鍵字
      const matchedKeywords = importantKeywords.filter(kw => title.includes(kw));
      const isImportant = matchedKeywords.length > 0;

      // 判斷分類
      let category = '📰 高雄房市';
      for (const cat of categoryMap) {
        if (cat.keywords.some(kw => title.includes(kw))) {
          category = cat.category;
          break;
        }
      }

      items.push({
        title,
        link: linkMatch ? linkMatch[1].trim() : '',
        pubDate: pubDate.toISOString(),
        source: sourceMatch ? sourceMatch[1].trim() : '未知來源',
        diffMinutes: Math.round(diffMinutes),
        isImportant,
        matchedKeywords,
        category
      });
    }
  }
}

if (items.length === 0) {
  return [{ json: { hasNews: false } }];
}

return items.map(item => ({ json: { hasNews: true, ...item } }));

